{"code":"import json, re
import pandas as pd

def load_records(v):
    if isinstance(v, str) and v.endswith('.json'):
        with open(v, 'r', encoding='utf-8') as f:
            return json.load(f)
    return v

recs = load_records(var_call_L8fDs73ZbOWv1aufcn7fQYRG)

def parse_pubnum(s):
    return s.strip() if isinstance(s, str) else None

# Build mapping: cited_pub -> set(uc_pub)
uc_pubs = set()
uc_cited = set()
for r in recs:
    pi = r.get('Patents_info','')
    m = re.search(r'pub\. number\s+([A-Z]{2}-[0-9]+[^\s\.,]*)', pi)
    if not m:
        m = re.search(r'pub\. number\s+([A-Z]{2}\s*[0-9]+[^\s\.,]*)', pi)
    uc_pub = m.group(1) if m else None
    if uc_pub:
        uc_pubs.add(uc_pub)
    cit = r.get('citation')
    try:
        cit_list = json.loads(cit) if isinstance(cit, str) and cit.strip().startswith('[') else []
    except Exception:
        cit_list = []
    for c in cit_list:
        pn = parse_pubnum(c.get('publication_number'))
        if pn:
            uc_cited.add(pn)

# Now find all publications that cite any UC publication number
# use SQL LIKE for each prefix? We'll just fetch rows where citation contains 'US-' etc and filter in python
print('__RESULT__:')
print(json.dumps({'uc_publications_count': len(uc_pubs), 'unique_cited_pubnums_in_uc_patents': len(uc_cited), 'sample_uc_pubnums': sorted(list(uc_pubs))[:10]}))"}

{"code":"import json, re

def load_records(v):
    if isinstance(v, str) and v.endswith('.json'):
        with open(v, 'r', encoding='utf-8') as f:
            return json.load(f)
    return v

uc_recs = load_records(var_call_L8fDs73ZbOWv1aufcn7fQYRG)
all_citing = load_records(var_call_83ldsRl8mhGM7kfK3kFRZn1Q)

# UC publication numbers set
uc_pubnums=set()
for r in uc_recs:
    pi=r.get('Patents_info','')
    m=re.search(r'pub\. number\s+([A-Z]{2}-[0-9A-Z]+[^\s\.,]*)', pi)
    if m:
        uc_pubnums.add(m.group(1))

# build pairs: (assignee, primary_cpc_subclass)
rows=[]
for r in all_citing:
    cit=r.get('citation','')
    if not (isinstance(cit,str) and cit.strip().startswith('[')):
        continue
    try:
        cit_list=json.loads(cit)
    except Exception:
        continue
    cites_uc=False
    for c in cit_list:
        pn=c.get('publication_number')
        if pn in uc_pubnums:
            cites_uc=True
            break
    if not cites_uc:
        continue
    pi=r.get('Patents_info','')
    # assignee is before ' holds' or 'In US, the ... is assigned to'
    m=re.match(r'^(.+?)\s+holds\s+the\s+', pi)
    if not m:
        m=re.search(r'is\s+(?:assigned|owned)\s+by\s+([^\s].+?)(?:\s+and\s+has|\s+with|\.)', pi)
    assignee=m.group(1).strip() if m else None
    if not assignee:
        continue
    if 'UNIV CALIFORNIA' in assignee:
        continue
    # primary CPC subclass: from cpc json entries where first==true; take code and reduce to subclass (first 4 + letter?) Actually CPC subclass is like A61K; take first 4 chars.
    cpc=r.get('cpc','')
    primary_sub=None
    if isinstance(cpc,str) and cpc.strip().startswith('['):
        try:
            cpc_list=json.loads(cpc)
            first_codes=[e.get('code') for e in cpc_list if e.get('first')==True and e.get('code')]
            code=first_codes[0] if first_codes else (cpc_list[0].get('code') if cpc_list else None)
            if code:
                primary_sub=code[:4]
        except Exception:
            pass
    if primary_sub:
        rows.append({'assignee':assignee,'subclass':primary_sub})

# unique pairs
uniq=sorted({(r['assignee'], r['subclass']) for r in rows})
print('__RESULT__:')
print(json.dumps({'pairs':uniq, 'count_pairs':len(uniq), 'count_assignees':len({a for a,_ in uniq})}))"}

{"code":"import json, re

def load_records(v):
    if isinstance(v, str) and v.endswith('.json'):
        with open(v, 'r', encoding='utf-8') as f:
            return json.load(f)
    return v

uc_recs = load_records(var_call_L8fDs73ZbOWv1aufcn7fQYRG)
all_citing = load_records(var_call_83ldsRl8mhGM7kfK3kFRZn1Q)

# UC publication numbers set
uc_pubnums=set()
for r in uc_recs:
    pi=r.get('Patents_info','')
    m=re.search(r'pub\. number\s+([A-Z]{2}-[0-9A-Z]+[^\s\.,]*)', pi)
    if m:
        uc_pubnums.add(m.group(1).strip())

_norm_re=re.compile(r'\s+')

def norm_pn(pn):
    if pn is None:
        return None
    pn=str(pn).strip()
    pn=_norm_re.sub('', pn)
    pn=pn.replace('–','-').replace('−','-')
    return pn

uc_norm=set(norm_pn(p) for p in uc_pubnums if p)

pairs=set()
for r in all_citing:
    cit=r.get('citation','')
    if not (isinstance(cit,str) and cit.strip().startswith('[')):
        continue
    try:
        cit_list=json.loads(cit)
    except Exception:
        continue
    if not any(norm_pn(c.get('publication_number')) in uc_norm for c in cit_list):
        continue
    pi=r.get('Patents_info','')
    m=re.match(r'^(.+?)\s+holds\s+the\s+', pi)
    if not m:
        m=re.search(r'is\s+held\s+by\s+([^\s].+?)(?:\s+and\s+has|\s+with|\.)', pi)
    if not m:
        m=re.search(r'is\s+(?:assigned|owned)\s+by\s+([^\s].+?)(?:\s+and\s+has|\s+with|\.)', pi)
    assignee=m.group(1).strip() if m else None
    if not assignee or 'UNIV CALIFORNIA' in assignee:
        continue
    cpc=r.get('cpc','')
    subclass=None
    if isinstance(cpc,str) and cpc.strip().startswith('['):
        try:
            cpc_list=json.loads(cpc)
            first_codes=[e.get('code') for e in cpc_list if e.get('first')==True and e.get('code')]
            code=first_codes[0] if first_codes else (cpc_list[0].get('code') if cpc_list else None)
            if code:
                subclass=code[:4]
        except Exception:
            pass
    if subclass:
        pairs.add((assignee,subclass))

print('__RESULT__:')
print(json.dumps({'pairs':sorted(list(pairs))}))"}

